        if (rc == NGX_HTTP_FORBIDDEN
            || rc == NGX_HTTP_UNAUTHORIZED
            || rc == NGX_HTTP_PROXY_AUTH_REQUIRED)
        {
            if (r->access_code != NGX_HTTP_UNAUTHORIZED
                && r->access_code != NGX_HTTP_PROXY_AUTH_REQUIRED)
